// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract MembershipAirdrop {
    address private _owner;
    mapping(address => uint256) private _tierOf;
    mapping(address => bool) private _claimed;
    mapping(address => uint256) private _airdropCredits;
    mapping(address => uint256) private _purchasedTokens;

    event TierSet(address indexed user, uint256 tier);
    event AirdropClaimed(address indexed user, uint256 credits);
    event TokensPurchased(address indexed user, uint256 amount);
    event Withdrawal(address indexed owner, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not owner");
        _;
    }

    constructor() {
        _owner = msg.sender;
    }

    function setTier(address user, uint256 tier) external onlyOwner {
        require(_tierOf[user] == 0, "Tier already set");
        _tierOf[user] = tier;
        emit TierSet(user, tier);
    }

    function tierOf(address user) public view returns (uint256) {
        return _tierOf[user];
    }

    function claimed(address user) public view returns (bool) {
        return _claimed[user];
    }

    function airdropCredits(address user) public view returns (uint256) {
        return _airdropCredits[user];
    }

    function purchasedTokens(address user) public view returns (uint256) {
        return _purchasedTokens[user];
    }

    function claimAirdrop() external {
        require(_tierOf[msg.sender] > 0, "No tier");
        require(!_claimed[msg.sender], "Already claimed");
        _claimed[msg.sender] = true;
        _airdropCredits[msg.sender] += _tierOf[msg.sender] * 100;
        emit AirdropClaimed(msg.sender, _tierOf[msg.sender] * 100);
    }

    function purchaseTokens() external payable {
        require(msg.value > 0, "Zero value");
        require(_tierOf[msg.sender] > 0, "No tier");
        uint256 tokenAmount = msg.value * 1000 / 1 ether;
        _purchasedTokens[msg.sender] += tokenAmount;
        emit TokensPurchased(msg.sender, tokenAmount);
    }

    function withdrawAll() external onlyOwner {
        uint256 balance = address(this).balance;
        (bool sent, ) = _owner.call{value: balance}("");
        require(sent, "Failed to send Ether");
        emit Withdrawal(_owner, balance);
    }
}
